SELECT id, member_id, transaction_type, amount, points, balance_after, points_after, business_no, remark, operator, created_at, updated_at, deleted FROM clinic_member_transaction WHERE deleted = 0
AND (transaction_type LIKE CONCAT('%', #{keyword}, '%') OR business_no LIKE CONCAT('%', #{keyword}, '%') OR operator LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}
